    inset: 0;
    display: flex;
    flex-direction: column;
    transform: translateX(100%);
    transition: transform 0.35s cubic-bezier(0.4, 0, 0.2, 1);
    will-change: transform;
    background: linear-gradient(160deg, var(--bg-start) 0%, var(--bg-end) 100%);
    overflow: hidden;
}

.screen.active {
    transform: translateX(0);
}

.screen.slide-out {
    transform: translateX(-40%);
    transition: transform 0.35s cubic-bezier(0.4, 0, 0.2, 1);
}

.screen-content {
    display: flex;
    flex-direction: column;
    height: 100%;
}

.screen-top {
    flex: 1;
    overflow: hidden;
    padding: 0 var(--pad-h);
    padding-top: env(safe-area-inset-top, 20px);
    padding-top: max(env(safe-area-inset-top, 20px), 20px);
}

.screen-top.scrollable {
    overflow-y: auto;
    -webkit-overflow-scrolling: touch;
    padding-bottom: 8px;
}

.screen-bottom {
    padding: 12px var(--pad-h);
    padding-bottom: max(env(safe-area-inset-bottom, 16px), 20px);
    background: linear-gradient(to top, rgba(248,249,251,0.98) 60%, transparent);
}

.sticky-bottom {
    box-shadow: 0 -1px 0 rgba(0,0,0,0.05);
}

/* ============================================
   APP LOGO (Screen 1)
============================================ */

.app-logo {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 18px 0 12px;
}

.app-logo__icon {
    font-size: 28px;
    line-height: 1;
}

