/**
 * Housekeeping Report App
 * Screens: room-input → camera → report → success
 */

// ============================================================
// STATE
// ============================================================
const state = {
    roomId: '',
    photos: [],          // array of { blob, dataUrl, s3Url }
    voiceText: '',
    mediaStream: null,
    mediaRecorder: null,
    audioChunks: [],
    isRecording: false,
    recordingTimer: null,
    recordingSeconds: 0,
    speechRecognition: null,
};

// ============================================================
// SCREEN NAVIGATION
// ============================================================

const SCREENS = ['screen-room-input', 'screen-camera', 'screen-report', 'screen-success'];

function goToScreen(id) {
    const current = document.querySelector('.screen.active');
    const next = document.getElementById(id);
    if (!next || current === next) return;

    const currentIdx = SCREENS.indexOf(current?.id);
    const nextIdx = SCREENS.indexOf(id);
    const forward = nextIdx > currentIdx;

    // Setup positions
    next.style.transform = forward ? 'translateX(100%)' : 'translateX(-40%)';
    next.style.transition = 'none';
    next.classList.add('active');

    // Force reflow
    next.getBoundingClientRect();

    // Animate in
    next.style.transition = 'transform 0.35s cubic-bezier(0.4,0,0.2,1)';
    next.style.transform = 'translateX(0)';

    // Animate out current
    if (current) {
        current.style.transition = 'transform 0.35s cubic-bezier(0.4,0,0.2,1)';
        current.style.transform = forward ? 'translateX(-40%)' : 'translateX(100%)';
        setTimeout(() => {
            current.classList.remove('active');
            current.style.transform = '';
            current.style.transition = '';
        }, 360);
    }

    // Lifecycle hooks
    if (id === 'screen-camera') onEnterCamera();
    if (id === 'screen-report') onEnterReport();
    if (id === 'screen-success') onEnterSuccess();
    if (id === 'screen-room-input') onEnterRoomInput();
}

// ============================================================
// TOAST
// ============================================================

let toastTimer = null;
function showToast(msg, duration = 2800) {
    const el = document.getElementById('toast');
    el.textContent = msg;
    el.classList.remove('hidden');
    el.classList.add('show');
    clearTimeout(toastTimer);
    toastTimer = setTimeout(() => {
        el.classList.remove('show');
        setTimeout(() => el.classList.add('hidden'), 310);
    }, duration);
}

// ============================================================
// SCREEN 1 – ROOM INPUT
// ============================================================

function onEnterRoomInput() {
    state.roomId = '';
    state.photos = [];
    state.voiceText = '';

    const input = document.getElementById('room-input');
    const btn = document.getElementById('btn-room-continue');
    input.value = '';
    btn.disabled = true;
    document.getElementById('room-input-error').classList.add('hidden');

    setTimeout(() => input.focus(), 400);
}

function initRoomInput() {
    const input = document.getElementById('room-input');
    const btn = document.getElementById('btn-room-continue');
    const err = document.getElementById('room-input-error');

    input.addEventListener('input', () => {
        const val = input.value.trim();
        btn.disabled = val.length === 0;
        if (val.length > 0) err.classList.add('hidden');
    });

    input.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' && !btn.disabled) proceedFromRoomInput();
    });

    btn.addEventListener('click', proceedFromRoomInput);
}

function proceedFromRoomInput() {
    const input = document.getElementById('room-input');
    const err = document.getElementById('room-input-error');
    const val = input.value.trim();

    if (!val) {
        err.classList.remove('hidden');
        showToast('Vui lòng nhập mã phòng');
        return;
    }

    state.roomId = val.toUpperCase();
    goToScreen('screen-camera');
}

// ============================================================
// SCREEN 2 – CAMERA
// ============================================================

function onEnterCamera() {
    updateRoomBadges();
    updatePhotoCounter();
    renderThumbnails();
    startCamera();
}

function updateRoomBadges() {
    document.getElementById('camera-room-badge').textContent = 'PHÒNG ' + state.roomId;
    document.getElementById('report-room-badge').textContent = 'PHÒNG ' + state.roomId;
    document.getElementById('success-room-name').textContent = state.roomId;
}

async function startCamera() {
    const video = document.getElementById('camera-video');
    const placeholder = document.getElementById('camera-placeholder');

    // Show placeholder
    placeholder.style.display = 'flex';

    try {
        if (state.mediaStream) {
            state.mediaStream.getTracks().forEach(t => t.stop());
        }
        state.mediaStream = await navigator.mediaDevices.getUserMedia({
            video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 960 } },
            audio: false
        });
        video.srcObject = state.mediaStream;
        await video.play();
        placeholder.style.display = 'none';
    } catch (e) {
        console.warn('Camera error:', e);
        placeholder.querySelector('.camera-placeholder__icon').textContent = '⚠️';
        placeholder.querySelector('.camera-placeholder__text').textContent = 'Không thể mở camera';
    }
}

function stopCamera() {
    if (state.mediaStream) {
        state.mediaStream.getTracks().forEach(t => t.stop());
        state.mediaStream = null;
    }
    const video = document.getElementById('camera-video');
    video.srcObject = null;
}

function capturePhoto() {
    if (state.photos.length >= 3) {
        showToast('Tối đa 3 ảnh');
        return;
    }

    const video = document.getElementById('camera-video');
    const canvas = document.getElementById('camera-canvas');

    if (!video.srcObject) {
        showToast('Camera chưa sẵn sàng');
        return;
    }

    canvas.width = video.videoWidth || 1280;
    canvas.height = video.videoHeight || 960;
    canvas.getContext('2d').drawImage(video, 0, 0);

    canvas.toBlob((blob) => {
        const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
        state.photos.push({ blob, dataUrl, s3Url: null });
        renderThumbnails();
        updatePhotoCounter();

        // Flash animation
        const wrap = document.getElementById('camera-wrap');
        wrap.style.filter = 'brightness(2)';
        setTimeout(() => { wrap.style.filter = ''; }, 120);

        // Auto-navigate at 3 photos
        if (state.photos.length === 3) {
            showToast('Đã chụp đủ 3 ảnh!');
            setTimeout(() => goToScreen('screen-report'), 800);
        } else {
            updateContinueBtn();
        }
    }, 'image/jpeg', 0.85);
}

function updatePhotoCounter() {
    document.getElementById('photo-counter').textContent = state.photos.length + ' / 3';
    document.getElementById('photo-count-label').textContent = state.photos.length;
}

function updateContinueBtn() {
    const btn = document.getElementById('btn-camera-continue');
    if (state.photos.length > 0 && state.photos.length < 3) {
        btn.classList.remove('hidden');
    } else {
        btn.classList.add('hidden');
    }
}

function renderThumbnails() {
    for (let i = 0; i < 3; i++) {
        const slot = document.getElementById('slot-' + i);
        if (!slot) continue;
        const photo = state.photos[i];
        if (photo) {
            slot.classList.remove('empty');
            slot.classList.add('filled');
            slot.innerHTML = `
                <img src="${photo.dataUrl}" alt="Ảnh ${i+1}">
                <button class="thumbnail-delete" onclick="deletePhoto(${i})">✕</button>
            `;
        } else {
            slot.classList.add('empty');
            slot.classList.remove('filled');
            slot.innerHTML = `<span class="thumbnail-slot__num">${i + 1}</span>`;
        }
    }
    updateContinueBtn();
}

function deletePhoto(idx) {
    state.photos.splice(idx, 1);
    renderThumbnails();
    updatePhotoCounter();
}

function initCamera() {
    document.getElementById('btn-shutter').addEventListener('click', capturePhoto);
    document.getElementById('btn-camera-back').addEventListener('click', () => {
        stopCamera();
        goToScreen('screen-room-input');
    });
    document.getElementById('btn-camera-continue').addEventListener('click', () => {
        if (state.photos.length === 0) {
            showToast('Cần ít nhất 1 ảnh');
            return;
        }
        goToScreen('screen-report');
    });
}

// ============================================================
// SCREEN 3 – REPORT
// ============================================================

function onEnterReport() {
    stopCamera();
    renderReportPhotos();
    setupVoiceRecording();
    document.getElementById('report-error').classList.add('hidden');
    // Restore previous transcript
    document.getElementById('voice-transcript').value = state.voiceText;
}

function renderReportPhotos() {
    const container = document.getElementById('report-photos');
    if (state.photos.length === 0) {
        container.innerHTML = '<p style="color:var(--text-muted);font-size:13px;font-weight:600">Chưa có ảnh nào</p>';
        return;
    }
    container.innerHTML = state.photos.map((p, i) =>
        `<div class="report-photo-thumb">
            <img src="${p.dataUrl}" alt="Ảnh ${i+1}">
        </div>`
    ).join('');
}

// Voice recording
function setupVoiceRecording() {
    const btn = document.getElementById('btn-mic');
    const icon = document.getElementById('mic-icon');
    const statusEl = document.getElementById('voice-status');
    const timerEl = document.getElementById('voice-timer');
    const waveform = document.getElementById('waveform');
    const transcript = document.getElementById('voice-transcript');

    // Reset
    btn.classList.remove('recording');
    icon.textContent = '🎙';
    statusEl.textContent = 'Nhấn để ghi âm';
    timerEl.classList.add('hidden');
    waveform.classList.add('hidden');
    state.isRecording = false;

    btn.onclick = () => {
        if (state.isRecording) {
            stopRecording();
        } else {
            startRecording();
        }
    };
}

function startRecording() {
    const icon = document.getElementById('mic-icon');
    const statusEl = document.getElementById('voice-status');
    const timerEl = document.getElementById('voice-timer');
    const waveform = document.getElementById('waveform');
    const btn = document.getElementById('btn-mic');

    // Try Web Speech API first
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (SpeechRecognition) {
        const recognition = new SpeechRecognition();
        recognition.lang = 'vi-VN';
        recognition.continuous = true;
        recognition.interimResults = true;
        state.speechRecognition = recognition;

        let finalText = document.getElementById('voice-transcript').value;

        recognition.onresult = (e) => {
            let interim = '';
            for (let i = e.resultIndex; i < e.results.length; i++) {
                const t = e.results[i][0].transcript;
                if (e.results[i].isFinal) {
                    finalText += (finalText ? ' ' : '') + t;
                } else {
                    interim = t;
                }
            }
            document.getElementById('voice-transcript').value = finalText + (interim ? ' ' + interim : '');
        };

        recognition.onerror = (e) => {
            console.warn('Speech error:', e.error);
            stopRecording();
        };

        recognition.onend = () => {
            if (state.isRecording) stopRecording();
        };

        recognition.start();
    }

    // Start timer
    state.isRecording = true;
    state.recordingSeconds = 0;
    btn.classList.add('recording');
    icon.textContent = '⏹';
    statusEl.textContent = 'Đang ghi âm... Nhấn để dừng';
    timerEl.classList.remove('hidden');
    waveform.classList.remove('hidden');
    updateTimer();
    state.recordingTimer = setInterval(updateTimer, 1000);
}

function updateTimer() {
    state.recordingSeconds++;
    const m = String(Math.floor(state.recordingSeconds / 60)).padStart(2, '0');
    const s = String(state.recordingSeconds % 60).padStart(2, '0');
    document.getElementById('voice-timer').textContent = m + ':' + s;

    // Max 2 minutes
    if (state.recordingSeconds >= 120) stopRecording();
}

function stopRecording() {
    clearInterval(state.recordingTimer);
    state.isRecording = false;

    if (state.speechRecognition) {
        try { state.speechRecognition.stop(); } catch(e) {}
        state.speechRecognition = null;
    }

    const icon = document.getElementById('mic-icon');
    const statusEl = document.getElementById('voice-status');
    const timerEl = document.getElementById('voice-timer');
    const waveform = document.getElementById('waveform');
    const btn = document.getElementById('btn-mic');

    btn.classList.remove('recording');
    icon.textContent = '🎙';

    const transcript = document.getElementById('voice-transcript').value.trim();
    if (transcript) {
        statusEl.textContent = 'Ghi âm xong ✓';
        state.voiceText = transcript;
    } else {
        statusEl.textContent = 'Nhấn để ghi âm lại';
    }
    timerEl.classList.add('hidden');
    waveform.classList.add('hidden');
}

function initReport() {
    document.getElementById('btn-report-back').addEventListener('click', () => {
        // Save transcript
        state.voiceText = document.getElementById('voice-transcript').value;
        stopRecording();
        goToScreen('screen-camera');
        setTimeout(() => startCamera(), 350);
    });

    document.getElementById('btn-submit').addEventListener('click', submitReport);

    document.getElementById('voice-transcript').addEventListener('input', (e) => {
        state.voiceText = e.target.value;
    });
}

// ============================================================
// SUBMIT REPORT (S3 upload + API)
// ============================================================

async function submitReport() {
    if (state.photos.length === 0) {
        document.getElementById('report-error').classList.remove('hidden');
        showToast('Cần ít nhất 1 ảnh để gửi báo cáo');
        return;
    }
    document.getElementById('report-error').classList.add('hidden');

    const overlay = document.getElementById('upload-overlay');
    const progressText = document.getElementById('upload-progress-text');
    overlay.classList.remove('hidden');

    try {
        // 1. Upload photos to S3
        const s3Urls = [];
        for (let i = 0; i < state.photos.length; i++) {
            progressText.textContent = `Đang tải ảnh ${i + 1}/${state.photos.length}...`;
            const url = await uploadPhotoToS3(state.photos[i].blob, i);
            s3Urls.push(url);
        }

        // 2. Submit report to backend
        progressText.textContent = 'Đang lưu báo cáo...';
        const transcript = document.getElementById('voice-transcript').value.trim();

        await api.post('/api/reports', {
            room_id: state.roomId,
            photos: s3Urls,
            voice_text: transcript || null,
        });

        overlay.classList.add('hidden');
        state.voiceText = transcript;
        goToScreen('screen-success');

    } catch (err) {
        overlay.classList.add('hidden');
        console.error('Submit error:', err);
        showToast('Lỗi: ' + (err.message || 'Không thể gửi báo cáo'), 3500);
    }
}

async function uploadPhotoToS3(blob, idx) {
    try {
        const filename = `housekeeping_${state.roomId}_${Date.now()}_${idx}.jpg`;
        const { upload_url, file_url } = await api.post('/api/upload/presigned-url', { filename });
        await fetch(upload_url, {
            method: 'PUT',
            body: blob,
            headers: { 'Content-Type': 'image/jpeg' },
        });
        return file_url;
    } catch (err) {
        console.warn('S3 upload failed, using placeholder:', err.message);
        // Fallback: return a placeholder so report can still be submitted
        return `photo_${idx + 1}_unavailable`;
    }
}

// ============================================================
// SCREEN 4 – SUCCESS
// ============================================================

function onEnterSuccess() {
    document.getElementById('success-room-name').textContent = state.roomId;

    const count = state.photos.length;
    document.getElementById('success-photo-count').textContent = count + (count === 1 ? ' ảnh' : ' ảnh');

    const now = new Date();
    document.getElementById('success-time').textContent =
        String(now.getHours()).padStart(2, '0') + ':' +
        String(now.getMinutes()).padStart(2, '0');

    // Countdown auto-redirect
    let secs = 3;
    document.getElementById('countdown').textContent = secs;
    const hint = document.getElementById('auto-redirect-hint');
    hint.style.display = 'block';

    const timer = setInterval(() => {
        secs--;
        document.getElementById('countdown').textContent = secs;
        if (secs <= 0) {
            clearInterval(timer);
            goToScreen('screen-room-input');
        }
    }, 1000);

    // Store timer ref so manual btn can clear it
    state._successTimer = timer;
}

function initSuccess() {
    document.getElementById('btn-new-room').addEventListener('click', () => {
        clearInterval(state._successTimer);
        goToScreen('screen-room-input');
    });
}

// ============================================================
// INIT
// ============================================================

document.addEventListener('DOMContentLoaded', () => {
    initRoomInput();
    initCamera();
    initReport();
    initSuccess();

    // Focus room input on load
    setTimeout(() => {
        const input = document.getElementById('room-input');
        if (input) input.focus();
    }, 300);
});
